# Demo map — Planet Engine text format
# Each line defines one property of an object.
# Multiple lines with the same name define one object.
# Use _none for unnamed scene objects.

# Ground plane
[_none]:[Plane](SCALE) = 20,1,20
[_none]:[Plane](COLOR) = 0.3,0.3,0.35,1.0
[_none]:[Plane](POSITION) = 0,-0.5,0

# Sun light
[Sun]:[_none](LIGHT_DIRECTIONAL)
[Sun]:[_none](COLOR) = 1.0,0.95,0.85
[Sun]:[_none](ROTATION) = 45,-30,0

# Templates (scripts can create these via Map.createObject)
[wall]:[Box](SCALE) = 3,3,0.15
[wall]:[Box](COLOR) = 0.6,0.6,0.6,1.0

[pillar]:[Cylinder](SCALE) = 0.4,3.0,0.4
[pillar]:[Cylinder](COLOR) = 0.5,0.4,0.3,1.0

[sphere]:[Sphere](SCALE) = 1,1,1
[sphere]:[Sphere](COLOR) = 0.8,0.2,0.2,1.0

[torch]:[Cylinder](SCALE) = 0.15,0.8,0.15
[torch]:[Cylinder](COLOR) = 0.6,0.5,0.2,1.0
